{
  "children": [
    {
      "name": "ValidateBuildRequest",
      "purpose": "Validate the build_request JSON structure and required fields based on action",
      "behavior": "Check action is one of trigger/status/list/cancel; for trigger, ensure repo and config present; for status/cancel, ensure build_id present; return validation result",
      "boundary": {
        "in_scope": [
          "validate action",
          "validate required fields",
          "check field types"
        ],
        "out_of_scope": [
          "business logic",
          "database access",
          "execution"
        ]
      },
      "preconditions": [
        "build_request is a dict"
      ],
      "postconditions": [
        "validation_result contains either valid request or error message"
      ],
      "guarantees": [
        "no side effects",
        "pure validation"
      ],
      "composition_role": "validate",
      "stop_decompose": true,
      "stop_reason": "pure validation function",
      "inputs": [
        {
          "name": "build_request",
          "type": "dict",
          "description": "the incoming request JSON",
          "source": "parent input"
        }
      ],
      "outputs": [
        {
          "name": "validation_result",
          "type": "dict",
          "description": "validated request or error",
          "consumer": "parent"
        }
      ],
      "signature": "def ValidateBuildRequest(build_request: dict) -> dict"
    },
    {
      "name": "CheckConcurrentBuild",
      "purpose": "Check if a build is already running for the given repo+branch",
      "behavior": "Query builds data store for any build with same repo and branch and status 'running' or 'queued'; return boolean",
      "boundary": {
        "in_scope": [
          "query builds by repo and branch",
          "check status"
        ],
        "out_of_scope": [
          "triggering",
          "cancelling",
          "listing"
        ]
      },
      "preconditions": [
        "repo and branch are non-empty strings"
      ],
      "postconditions": [
        "no state change"
      ],
      "guarantees": [
        "read-only access to builds"
      ],
      "composition_role": "query",
      "stop_decompose": true,
      "stop_reason": "atomic database query",
      "inputs": [
        {
          "name": "repo",
          "type": "str",
          "description": "repository name",
          "source": "parent input"
        },
        {
          "name": "branch",
          "type": "str",
          "description": "branch name",
          "source": "parent input"
        }
      ],
      "outputs": [
        {
          "name": "is_concurrent",
          "type": "bool",
          "description": "true if a build is already running",
          "consumer": "parent"
        }
      ],
      "signature": "def CheckConcurrentBuild(repo: str, branch: str) -> bool"
    },
    {
      "name": "CreateBuildRecord",
      "purpose": "Create a new build record in the builds data store",
      "behavior": "Generate a unique build_id, set status to 'queued', store repo, branch, config, started_at, empty logs, return build_id",
      "boundary": {
        "in_scope": [
          "generate build_id",
          "insert record",
          "set initial status"
        ],
        "out_of_scope": [
          "execution",
          "cancelling",
          "listing"
        ]
      },
      "preconditions": [
        "no concurrent build for same repo+branch"
      ],
      "postconditions": [
        "new build record exists with status 'queued'"
      ],
      "guarantees": [
        "build_id is unique",
        "record is persisted"
      ],
      "composition_role": "mutate",
      "stop_decompose": true,
      "stop_reason": "atomic database write",
      "inputs": [
        {
          "name": "repo",
          "type": "str",
          "description": "repository name",
          "source": "parent input"
        },
        {
          "name": "branch",
          "type": "str",
          "description": "branch name",
          "source": "parent input"
        },
        {
          "name": "config",
          "type": "dict",
          "description": "build configuration with steps",
          "source": "parent input"
        }
      ],
      "outputs": [
        {
          "name": "build_id",
          "type": "str",
          "description": "unique identifier for the build",
          "consumer": "parent"
        }
      ],
      "signature": "def CreateBuildRecord(repo: str, branch: str, config: dict) -> str"
    },
    {
      "name": "ExecuteBuildSteps",
      "purpose": "Run the build steps: compile, test, package artifacts, update status and logs incrementally",
      "behavior": "Iterate over config.build_steps, execute each step, append logs, update status to 'running' then 'completed' or 'failed', store artifacts",
      "boundary": {
        "in_scope": [
          "execute steps",
          "log output",
          "update status",
          "store artifacts"
        ],
        "out_of_scope": [
          "validation",
          "concurrency check",
          "listing"
        ]
      },
      "preconditions": [
        "build record exists with status 'queued'"
      ],
      "postconditions": [
        "build status is 'completed' or 'failed'",
        "logs are stored",
        "artifacts stored"
      ],
      "guarantees": [
        "incremental log storage",
        "atomic status update"
      ],
      "composition_role": "execute",
      "stop_decompose": false,
      "stop_reason": "can be further decomposed into compile, test, package",
      "inputs": [
        {
          "name": "build_id",
          "type": "str",
          "description": "the build to execute",
          "source": "previous child output"
        },
        {
          "name": "config",
          "type": "dict",
          "description": "build configuration with steps",
          "source": "parent input"
        }
      ],
      "outputs": [
        {
          "name": "execution_result",
          "type": "dict",
          "description": "final status and logs",
          "consumer": "parent"
        }
      ],
      "signature": "def ExecuteBuildSteps(build_id: str, config: dict) -> dict"
    },
    {
      "name": "QueryBuildStatus",
      "purpose": "Return current status and logs for a given build_id",
      "behavior": "Look up build record by build_id, return status and logs",
      "boundary": {
        "in_scope": [
          "query by build_id",
          "return status and logs"
        ],
        "out_of_scope": [
          "triggering",
          "cancelling",
          "listing"
        ]
      },
      "preconditions": [
        "build_id exists in builds"
      ],
      "postconditions": [
        "no state change"
      ],
      "guarantees": [
        "read-only access"
      ],
      "composition_role": "query",
      "stop_decompose": true,
      "stop_reason": "atomic database query",
      "inputs": [
        {
          "name": "build_id",
          "type": "str",
          "description": "the build to query",
          "source": "parent input"
        }
      ],
      "outputs": [
        {
          "name": "status",
          "type": "str",
          "description": "current build status",
          "consumer": "parent"
        },
        {
          "name": "logs",
          "type": "list",
          "description": "build logs",
          "consumer": "parent"
        }
      ],
      "signature": "def QueryBuildStatus(build_id: str) -> tuple[str, list]"
    },
    {
      "name": "ListBuilds",
      "purpose": "Return all builds filtered by optional repo, branch, status",
      "behavior": "Query builds data store, apply filters if provided, return list of build records",
      "boundary": {
        "in_scope": [
          "query builds",
          "apply filters",
          "return list"
        ],
        "out_of_scope": [
          "single build operations",
          "execution"
        ]
      },
      "preconditions": [
        "none"
      ],
      "postconditions": [
        "no state change"
      ],
      "guarantees": [
        "read-only access"
      ],
      "composition_role": "query",
      "stop_decompose": true,
      "stop_reason": "atomic database query",
      "inputs": [
        {
          "name": "repo",
          "type": "Optional[str]",
          "description": "optional filter",
          "source": "parent input"
        },
        {
          "name": "branch",
          "type": "Optional[str]",
          "description": "optional filter",
          "source": "parent input"
        },
        {
          "name": "status",
          "type": "Optional[str]",
          "description": "optional filter",
          "source": "parent input"
        }
      ],
      "outputs": [
        {
          "name": "builds_list",
          "type": "list",
          "description": "list of build records",
          "consumer": "parent"
        }
      ],
      "signature": "def ListBuilds(repo: Optional[str] = None, branch: Optional[str] = None, status: Optional[str] = None) -> list"
    },
    {
      "name": "CancelBuild",
      "purpose": "Cancel a running build: stop execution, update status to 'cancelled'",
      "behavior": "Check build status; if 'running' or 'queued', update status to 'cancelled' and append cancellation log; if already completed, no-op",
      "boundary": {
        "in_scope": [
          "check status",
          "update status",
          "append log"
        ],
        "out_of_scope": [
          "triggering",
          "listing",
          "execution"
        ]
      },
      "preconditions": [
        "build_id exists"
      ],
      "postconditions": [
        "if running/queued, status changed to 'cancelled' and log appended"
      ],
      "guarantees": [
        "no-op for completed builds"
      ],
      "composition_role": "mutate",
      "stop_decompose": true,
      "stop_reason": "atomic state update",
      "inputs": [
        {
          "name": "build_id",
          "type": "str",
          "description": "the build to cancel",
          "source": "parent input"
        }
      ],
      "outputs": [
        {
          "name": "cancel_result",
          "type": "dict",
          "description": "success or no-op indication",
          "consumer": "parent"
        }
      ],
      "signature": "def CancelBuild(build_id: str) -> dict"
    }
  ],
  "interface_preservation": {
    "parent_inputs_covered_by": {
      "build_request": [
        "ValidateBuildRequest"
      ],
      "repo": [
        "CheckConcurrentBuild",
        "CreateBuildRecord",
        "ListBuilds"
      ],
      "branch": [
        "CheckConcurrentBuild",
        "CreateBuildRecord",
        "ListBuilds"
      ],
      "config": [
        "CreateBuildRecord",
        "ExecuteBuildSteps"
      ],
      "build_id": [
        "QueryBuildStatus",
        "CancelBuild"
      ],
      "status": [
        "ListBuilds"
      ]
    },
    "parent_outputs_produced_by": {
      "build_result": [
        "ValidateBuildRequest",
        "CheckConcurrentBuild",
        "CreateBuildRecord",
        "ExecuteBuildSteps",
        "QueryBuildStatus",
        "ListBuilds",
        "CancelBuild"
      ]
    }
  },
  "dataflow_edges": [
    {
      "from_node": "parent",
      "from_output": "build_request",
      "to_node": "ValidateBuildRequest",
      "to_input": "build_request",
      "note": "validate input"
    },
    {
      "from_node": "ValidateBuildRequest",
      "from_output": "validation_result",
      "to_node": "parent",
      "to_input": "build_result",
      "note": "pass validation result"
    },
    {
      "from_node": "parent",
      "from_output": "repo",
      "to_node": "CheckConcurrentBuild",
      "to_input": "repo",
      "note": "only for trigger action"
    },
    {
      "from_node": "parent",
      "from_output": "branch",
      "to_node": "CheckConcurrentBuild",
      "to_input": "branch",
      "note": "only for trigger action"
    },
    {
      "from_node": "CheckConcurrentBuild",
      "from_output": "is_concurrent",
      "to_node": "parent",
      "to_input": "build_result",
      "note": "concurrency flag"
    },
    {
      "from_node": "parent",
      "from_output": "repo",
      "to_node": "CreateBuildRecord",
      "to_input": "repo",
      "note": "only if no concurrent build"
    },
    {
      "from_node": "parent",
      "from_output": "branch",
      "to_node": "CreateBuildRecord",
      "to_input": "branch",
      "note": "only if no concurrent build"
    },
    {
      "from_node": "parent",
      "from_output": "config",
      "to_node": "CreateBuildRecord",
      "to_input": "config",
      "note": "only if no concurrent build"
    },
    {
      "from_node": "CreateBuildRecord",
      "from_output": "build_id",
      "to_node": "parent",
      "to_input": "build_result",
      "note": "new build id"
    },
    {
      "from_node": "parent",
      "from_output": "build_id",
      "to_node": "ExecuteBuildSteps",
      "to_input": "build_id",
      "note": "execute steps"
    },
    {
      "from_node": "parent",
      "from_output": "config",
      "to_node": "ExecuteBuildSteps",
      "to_input": "config",
      "note": "execute steps"
    },
    {
      "from_node": "ExecuteBuildSteps",
      "from_output": "execution_result",
      "to_node": "parent",
      "to_input": "build_result",
      "note": "final status and logs"
    },
    {
      "from_node": "parent",
      "from_output": "build_id",
      "to_node": "QueryBuildStatus",
      "to_input": "build_id",
      "note": "for status action"
    },
    {
      "from_node": "QueryBuildStatus",
      "from_output": "status",
      "to_node": "parent",
      "to_input": "build_result",
      "note": "build details"
    },
    {
      "from_node": "QueryBuildStatus",
      "from_output": "logs",
      "to_node": "parent",
      "to_input": "build_result",
      "note": "build details"
    },
    {
      "from_node": "parent",
      "from_output": "repo",
      "to_node": "ListBuilds",
      "to_input": "repo",
      "note": "for list action"
    },
    {
      "from_node": "parent",
      "from_output": "branch",
      "to_node": "ListBuilds",
      "to_input": "branch",
      "note": "for list action"
    },
    {
      "from_node": "parent",
      "from_output": "status",
      "to_node": "ListBuilds",
      "to_input": "status",
      "note": "for list action"
    },
    {
      "from_node": "ListBuilds",
      "from_output": "builds_list",
      "to_node": "parent",
      "to_input": "build_result",
      "note": "filtered list"
    },
    {
      "from_node": "parent",
      "from_output": "build_id",
      "to_node": "CancelBuild",
      "to_input": "build_id",
      "note": "for cancel action"
    },
    {
      "from_node": "CancelBuild",
      "from_output": "cancel_result",
      "to_node": "parent",
      "to_input": "build_result",
      "note": "cancellation outcome"
    }
  ]
}
